import{_ as o,o as d,c as t,a2 as a}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"配置说明","description":"","frontmatter":{},"headers":[],"relativePath":"configuration.md","filePath":"configuration.md","lastUpdated":1781750850000}'),c={name:"configuration.md"};function i(n,e,s,l,r,h){return d(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="配置说明" tabindex="-1">配置说明 <a class="header-anchor" href="#配置说明" aria-label="Permalink to &quot;配置说明&quot;">​</a></h1><p>ECodex 的用户配置分为三类：运行时设置、自定义命令配置和兼容开关。</p><h2 id="运行时目录" tabindex="-1">运行时目录 <a class="header-anchor" href="#运行时目录" aria-label="Permalink to &quot;运行时目录&quot;">​</a></h2><p>默认运行时目录：<code>%USERPROFILE%\\.ecodex</code></p><p>常见文件：</p><table tabindex="0"><thead><tr><th>文件</th><th>用途</th></tr></thead><tbody><tr><td><code>settings.json</code></td><td>UI、终端行为、兼容开关等设置。</td></tr><tr><td><code>session.json</code></td><td>Workspace、Surface、Pane 布局与快照。</td></tr><tr><td><code>resume.json</code></td><td>tmux / agent 等恢复绑定。</td></tr><tr><td><code>daemon-debug.log</code></td><td>App / daemon / IPC 诊断日志。</td></tr></tbody></table><h2 id="ecodex-json-加载顺序" tabindex="-1"><code>ecodex.json</code> 加载顺序 <a class="header-anchor" href="#ecodex-json-加载顺序" aria-label="Permalink to &quot;`ecodex.json` 加载顺序&quot;">​</a></h2><p>自定义命令配置使用 <code>ecodex.json</code>。推荐路径：</p><ol><li>项目内：<code>.ecodex/ecodex.json</code></li><li>用户级：<code>%USERPROFILE%\\.config\\ecodex\\ecodex.json</code></li><li>兼容读取：<code>.cmux/cmux.json</code>（由兼容开关控制）</li></ol><p>执行诊断：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ecodex config diagnostics</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ecodex config reload</span></span></code></pre></div><h2 id="运行时行为设置" tabindex="-1">运行时行为设置 <a class="header-anchor" href="#运行时行为设置" aria-label="Permalink to &quot;运行时行为设置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>默认</th><th>说明</th></tr></thead><tbody><tr><td><code>PreserveDaemonSessionsOnClose</code></td><td><code>true</code></td><td>关闭按钮、托盘退出或 <code>app.exit</code> 退出 ECodex 时保留 daemon 托管终端；设为 <code>false</code> 时退出前逐个终止当前 daemon 会话。最小化保留任务栏按钮并后台运行，不触发该开关。</td></tr></tbody></table><h2 id="兼容开关" tabindex="-1">兼容开关 <a class="header-anchor" href="#兼容开关" aria-label="Permalink to &quot;兼容开关&quot;">​</a></h2><p>设置窗口的“高级”页包含兼容选项：</p><ul><li>监听旧主应用管道（<code>cmux</code>）。</li><li>监听旧 daemon 管道 / Mutex（<code>cmux-daemon</code>）。</li><li>读取旧配置文件 <code>.cmux/cmux.json</code>。</li><li>接受旧命令行命令别名。</li></ul><p>兼容能力只用于迁移；新配置应统一写入 <code>.ecodex/ecodex.json</code>。</p><h2 id="安全建议" tabindex="-1">安全建议 <a class="header-anchor" href="#安全建议" aria-label="Permalink to &quot;安全建议&quot;">​</a></h2><ul><li>不要在 <code>ecodex.json</code> 中写入真实 token 或 API key。</li><li>对自动执行命令使用 <code>confirm: true</code>。</li><li>附 issue 时先脱敏 <code>settings.json</code>、<code>resume.json</code> 和 <code>daemon-debug.log</code>。</li></ul>',19)])])}const x=o(c,[["render",i]]);export{u as __pageData,x as default};
